CustomField.formula:
IF ( NOT(ISBLANK(First_Order_Date_Import__c)), First_Order_Date_Import__c, IF( AND( ISBLANK(First_Order_Date_Final_Formula_Field__c), ISBLANK(First_Order_Date_from_Children_Account__c), ISBLANK(First_Order_Date_from_Parent_Account__c)
), NULL,
DATE(2998,1,1) - MAX( DATE(2998,1,1) - BLANKVALUE(First_Order_Date_Final_Formula_Field__c , DATE(2998,1,1)), DATE(2998,1,1) - BLANKVALUE(First_Order_Date_from_Children_Account__c, DATE(2998,1,1)), DATE(2998,1,1) - BLANKVALUE(First_Order_Date_from_Parent_Account__c ,DATE(2998,1,1)) ) ))
